# ANTI-PATTERN: Monolithic agent without task decomposition
class BatterAgent:
    def execute_match(self, match_state):
        # Tries to handle everything: analyzing bowler, predicting line,
        # managing fatigue, planning accelerations, managing pressure
        batting_decision = self.analyze_everything(match_state)
        return batting_decision

# BEST PRACTICE: Decomposed agent pattern with supervisor
class BowlerAnalysisAgent:
    def analyze(self, bowler_data):
        return {"weak_areas": [...], "pattern": "yorker_specialist"}

class FatigueManagementAgent:
    def assess(self, batter_state):
        return {"energy_level": 0.75, "safe_strike_rate": 45}

class PressureManagementAgent:
    def evaluate(self, match_state):
        return {"overs_remaining": 8, "risk_tolerance": 0.6}

class CaptainSupervisor:
    def coordinate_batting_decision(self, match_state):
        bowler_insight = self.bowler_agent.analyze(match_state.bowler)
        fatigue_constraint = self.fatigue_agent.assess(match_state.batter)
        pressure_context = self.pressure_agent.evaluate(match_state)

        # Integrate specialized decisions
        decision = self.integrate_insights(
            bowler_insight,
            fatigue_constraint,
            pressure_context
        )
        return decision

# Key difference: Anti-pattern creates cognitive overload and poor error handling.
# Best practice distributes concerns, enabling independent testing and reuse.
